parameters.inputSchema:
{
  "type": "object",
  "title": "Dermatology Morphology Extraction Schema",
  "description": "Structured extraction of only visible dermatologic features from an image, without any diagnostic inference.",
  "properties": {
    "morphology_grid": {
      "type": "object",
      "description": "Standardized representation of observable lesion morphology based strictly on visual assessment.",
      "additionalProperties": false,
      "properties": {
        "primary_lesion_type": {
          "type": "string",
          "description": "Primary visible lesion morphology such as macule, papule, plaque, vesicle, pustule, nodule, or patch."
        },
        "secondary_changes": {
          "type": "array",
          "description": "Visible secondary alterations such as erosion, ulceration, fissuring, excoriation, or lichenification.",
          "items": {
            "type": "string"
          }
        },
        "scale_presence": {
          "type": "string",
          "enum": [
            "absent",
            "mild",
            "moderate",
            "thick"
          ],
          "description": "Degree of visible scaling on the lesion surface. If uncertain, use visibility_limitations instead of assuming absence."
        },
        "scale_quality": {
          "type": "string",
          "enum": [
            "fine",
            "silvery",
            "greasy",
            "gritty",
            "not clearly inferable"
          ],
          "description": "Qualitative appearance of scale if present; use 'not clearly inferable' if scale characteristics cannot be determined."
        },
        "crust_type": {
          "type": "string",
          "description": "Type of visible crust, if present, such as serous, hemorrhagic, or honey-colored."
        },
        "surface_texture": {
          "type": "string",
          "description": "Observed surface texture such as smooth, rough, verrucous, or scaly."
        },
        "borders": {
          "type": "string",
          "description": "Visible characteristics of lesion margins such as well-defined, ill-defined, regular, or irregular."
        },
        "color": {
          "type": "string",
          "description": "Observed color(s) of the lesion such as erythematous, hyperpigmented, hypopigmented, violaceous, or mixed."
        },
        "induration_presence": {
          "type": "string",
          "enum": [
            "yes",
            "no",
            "not clearly inferable"
          ],
          "description": "Whether visible features suggest induration; use 'not clearly inferable' if this cannot be assessed visually."
        },
        "distribution_pattern": {
          "type": "string",
          "description": "Pattern of lesion distribution such as localized, generalized, linear, dermatomal, or symmetrical."
        },
        "follicular_involvement": {
          "type": "string",
          "description": "Indicates whether the lesion appears centered around or involving hair follicles based on visible features."
        }
      },
      "required": [
        "primary_lesion_type",
        "secondary_changes",
        "scale_presence",
        "scale_quality",
        "crust_type",
        "surface_texture",
        "borders",
        "color",
        "induration_presence",
        "distribution_pattern",
        "follicular_involvement"
      ]
    },
    "visibility_limitations": {
      "type": "string",
      "description": "Explicit description of any limitations in visual assessment such as poor lighting, blur, obstruction, or inability to confirm presence or absence of specific features (e.g., scaling)."
    }
  },
  "required": [
    "morphology_grid",
    "visibility_limitations"
  ]
}
